  ('pukao-0a2fc18c-moex-00068', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-113-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '有關耐久財的需求價格彈性，下列何者正確？', '["在短期較為敏感", "在長期較為敏感", "不隨時間長短期而有所改變", "較供給的價格彈性更為敏感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "422", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
